head.script:
//==================================================================================================================
// id       : op_601_01_02b 
// 이름     : 이트란스 COPARN조회
// 경로     : 물류/작업실적/입출고/반출입(자가)/이트란스 전송데이터 조회
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-18
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            () -  버튼 클릭
//==================================================================================================================
scwin.blNo;
scwin.bookingNo;
scwin.cntrNo;
scwin.dateFormat;
scwin.curDtm;
scwin.showmod = 0;
scwin.blNo 		    = ($c.data.getParameter("blNo") 	 == null) ? "" : $c.data.getParameter("blNo");
scwin.bookingNo  	= ($c.data.getParameter("bookingNo") == null) ? "" : $c.data.getParameter("bookingNo");
scwin.cntrNo 		= ($c.data.getParameter("cntrNo") 	 == null) ? "" : $c.data.getParameter("cntrNo");
scwin.dateFormat    = $c.date.getServerDateTime("yyyyMMddHHmm");
scwin.curDtm        = $c.date.getServerDateTime("yyyyMMdd");

scwin.onpageload = function() {
    ica_regDt.setValue(scwin.curDtm);
    ed_blNo.setValue(scwin.blNo);
    ed_bookingNo.setValue(scwin.bookingNo);
    ed_cntrNo.setValue(scwin.cntrNo);

    acb_docKnd.setValue("");
    acb_replyCls.setValue("");
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (){
    if($c.gus.cfIsNull(ed_blNo.getValue())
    && $c.gus.cfIsNull(ed_bookingNo.getValue())
    && $c.gus.cfIsNull(ed_cntrNo.getValue())
    && $c.gus.cfIsNull(ica_regDt.getValue())){
        await $c.win.alert("등록일자, BL_NO, BOOKING_NO, CNTR_NO 중 하나는  필수입력 사항입니다.");
        return;
    }
    if(!$c.gus.cfIsNull(ica_regDt.getValue())){
        if (!$c.gus.cfValidate([ica_regDt])) {
            return;
        }
    }
    $c.sbm.execute(sbm_retrieve);
};

